function fmt(a){if(!a)return'Undisclosed';if(a>=1e9)return'$'+(a/1e9).toFixed(1)+'B';if(a>=1e6)return'$'+(a/1e6).toFixed(0)+'M';if(a>=1e3)return'$'+(a/1e3).toFixed(0)+'K';return'$'+a}
