function getCountriesByContinent(){const m={};deals.forEach(d=>{if(!m[d.continent])m[d.continent]=new Set();m[d.continent].add(d.country)});const r={};Object.keys(m).sort().forEach(c=>{r[c]=[...m[c]].sort()});return r}
